                                                                                              $$, $$6d883643b5c140f4e191798f2e59ed12dd27d23e63be4ecdbffcaab8f8898997$$, $${"A": "40da1dd36bfab6d9d2fdfe6e1743efd440af26a08202170034f71c2094aca475", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "680e32a5652050b0ffc9a5a2c1498c43b812aa2995f8298bb16d96dca410abaf"}$$::jsonb, $$Budget J-Books/FY26/Navy/RDTEN_BA1-3_Book.pdf$$, 289, $$2026-05-10T04:03:06.372628+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0602792N$$, 2026, $$The Office of Naval Research (ONR) portfolio includes efforts that solve problems, respond to mission requirements, and perform exploratory research for new and
breakthrough capabilities, which will define the future of U.S. Naval forces. Larger in scope, scale, and risk Innovative Naval Prototypes (INP) are selected for their high-
payoff and potential to revolutionize operational concepts. Due to high technical risk, INPs typically have long durations with no more than three years between decision
points. They mature technologies from a Technology Readiness Level (TRL) of 2 or 3 to a TRL of 6. As such, INPs require both the Applied Research, detailed in this
PE; and Advanced Technology Development (ATD) funding, detailed in PE 0603801N. Developing INPs requires a systematic expansion and application of knowledge
to develop useful materials, devices, and systems oriented toward the design and development of prototypes applicable to specific mission area requirements. The
efforts funded within this PE translate promising basic research into solutions for broadly defined military needs. These efforts include developing breadboard hardware
and algorithms that establish the initial feasibility and practicality of proposed solutions to technological challenges, such as concept exploration efforts, studies,
